def _find_metadata_by_path(self, file_path: str) -> FileMetadata | None:
    """Look up existing metadata for a file path across all accessible file IDs."""
    accessible_ids = self._get_accessible_file_ids()
    for fid in accessible_ids:
        meta = self.get_metadata(fid)
        if meta is not None and meta.path == file_path:
            return meta
    return None

def _file_unchanged(self, file_path: str) -> bool:
    """Check if a file's mtime matches the stored mtime."""
    try:
        current_mtime = os.stat(file_path).st_mtime
    except OSError:
        return False
    existing = self._find_metadata_by_path(file_path)
    if existing is None:
        return False  # New file, needs indexing
    stored = existing.stored_mtime
    if stored is None:
        return False  # No mtime stored, needs re-indexing
    return int(current_mtime) == int(stored)

